// ─────────────────────────────────────────────
// VHSYS :: employers_plus_info
// Rota   : POST /employers_plus_info
// Fase 4 : Fluxo EMPLOYERS
// ─────────────────────────────────────────────
// Input  : { xml_ref: '<xjx><cmd t="campo">valor</cmd>...</xjx>' }
// Output : { message: '...', transformed_data: {...} } HTTP 201
// Banco  : UPSERT employersData + UPSERT/DELETE dependents + UPSERT/DELETE benefits
// Chave  : id_funcionario (main), SHA-256(id+nome_dep) (deps), SHA-256(id+nome_ben) (benefits)
// ─────────────────────────────────────────────

const body = $input.first().json.body || $input.first().json;

if (!body.xml_ref) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Missing required field: xml_ref' }
  };
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route    : 'employers_plus_info',
  event    : 'input_validated',
  level    : 'info'
}));

return { _valid: true, xml_ref: body.xml_ref };

// ─────────────────────────────────────────────
// Parse XML + Transform + Decode HTML + Parse Dates + Parse Floats
// Tudo em 1 nó para evitar perda de contexto entre nós.
// CORRIGIDO: sem require('xml2js') — parser nativo via regex.
// Equivale ao xmltodict.parse + transform_user_data do Flask.
// ─────────────────────────────────────────────

const xmlString = $input.first().json.xml_ref;

// ── 1. Parse XML <xjx><cmd t='campo'>valor</cmd></xjx> ──
const cmdRegex = /<cmd[^>]+t=["']([^"']+)["'][^>]*>([\s\S]*?)<\/cmd>/gi;
const rawDict  = {};
let match;
while ((match = cmdRegex.exec(xmlString)) !== null) {
  const key = match[1].trim();
  const val = match[2].trim();
  if (key) rawDict[key] = val;
}

if (Object.keys(rawDict).length === 0) {
  throw new Error('XML must contain a <xjx><cmd t="..."> structure.');
}

// ── 2. Decode HTML entities ──
function decodeHtml(s) {
  if (typeof s !== 'string') return s;
  return s
    .replace(/&amp;/g,  '&')
    .replace(/&lt;/g,   '<')
    .replace(/&gt;/g,   '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g,  "'")
    .replace(/&nbsp;/g, ' ');
}

// ── 3. transform_user_data: separa dependentes e benefícios por sufixo numérico ──
const dependentes = {};
const beneficios  = {};
const globalData  = {};
const numSuffix   = /_(\d+)$/;

for (const [key, rawVal] of Object.entries(rawDict)) {
  const val   = decodeHtml(rawVal);
  const mNum  = key.match(numSuffix);
  if (!mNum) {
    globalData[key] = val;
    continue;
  }
  const num     = mNum[1];
  const baseKey = key.substring(0, mNum.index);
  if (baseKey.includes('dependente')) {
    if (!dependentes[num]) dependentes[num] = {};
    dependentes[num][baseKey] = val;
  } else if (baseKey.includes('beneficio')) {
    if (!beneficios[num]) beneficios[num] = {};
    beneficios[num][baseKey] = val;
  }
}

// ── 4. Parse datas DD/MM/YYYY → ISO ──
function parseDate(s) {
  if (!s || typeof s !== 'string') return null;
  const m = s.match(/(\d{2})\/(\d{2})\/(\d{4})/);
  if (!m) return null;
  return `${m[3]}-${m[2]}-${m[1]}T00:00:00.000Z`;
}

// ── 5. Parse float BR (1.234,56 → 1234.56) ──
function parseBRFloat(v) {
  if (!v) return 0.0;
  let s = String(v).replace(/[^\d,.]/g, '');
  if (s.includes(',') && s.includes('.')) s = s.replace(/\./g, '').replace(',', '.');
  else if (s.includes(',')) s = s.replace(',', '.');
  return parseFloat(s) || 0.0;
}

// ── 6. Gera SHA-256 ──
const crypto = require('crypto');
function sha256(s) {
  return crypto.createHash('sha256').update(String(s)).digest('hex');
}

const idFuncionario  = globalData.id_funcionario  || '';
const nomeFuncionario = globalData.nome_funcionario || '';

const dependentesArr = Object.values(dependentes).map(dep => ({
  dependents_id    : sha256(`${idFuncionario}-${dep.nome_dependente || ''}`),
  id_funcionario   : idFuncionario,
  nome_funcionario : nomeFuncionario,
  nome_dependente  : dep.nome_dependente  || null,
  tipo_dependente  : dep.tipo_dependente  || null,
  fone_dependente  : dep.fone_dependente  || null,
  rg               : dep.rg               || null,
  cpf              : dep.cpf              || null,
  data_nascimento  : parseDate(dep.data_nascimento_dependente)
})).filter(d => d.nome_dependente);

const beneficiosArr = Object.values(beneficios).map(ben => ({
  benefit_id       : sha256(`${idFuncionario}-${ben.nome_beneficio || ''}`),
  id_funcionario   : idFuncionario,
  nome_funcionario : nomeFuncionario,
  nome             : ben.nome_beneficio   || null,
  valor            : parseBRFloat(ben.valor_beneficio)
})).filter(b => b.nome);

const transformed = {
  ...globalData,
  salario_funcionario          : parseBRFloat(globalData.salario_funcionario),
  data_admissao_funcionario    : parseDate(globalData.data_admissao_funcionario),
  data_nascimento_funcionario  : parseDate(globalData.data_nascimento_funcionario),
  dependentes : dependentesArr,
  beneficios  : beneficiosArr
};

console.log(JSON.stringify({
  timestamp        : new Date().toISOString(),
  route            : 'employers_plus_info',
  event            : 'xml_parsed_and_transformed',
  id_funcionario   : idFuncionario,
  nome_funcionario : nomeFuncionario,
  dependentes_count: dependentesArr.length,
  beneficios_count : beneficiosArr.length,
  level            : 'info'
}));

return { transformed_data: transformed };

// Expande cada dependente para um item separado
// Recupera transformed_data do nó de parse
const ctx = $('Parse + Transform').first().json.transformed_data;
const deps = ctx.dependentes || [];

if (deps.length === 0) {
  return [{ _no_deps: true, id_funcionario: ctx.id_funcionario, dependentes_ids: [] }];
}

return deps.map(dep => ({ ...dep, _all_ids: deps.map(d => d.dependents_id) }));

// Expande cada benefício para um item separado
const ctx = $('Parse + Transform').first().json.transformed_data;
const bens = ctx.beneficios || [];

if (bens.length === 0) {
  return [{ _no_bens: true, id_funcionario: ctx.id_funcionario, beneficios_ids: [] }];
}

return bens.map(ben => ({ ...ben, _all_ids: bens.map(b => b.benefit_id) }));

// Sucesso — HTTP 201 preserva compatibilidade com Flask
const ctx = $('Parse + Transform').first().json.transformed_data;

console.log(JSON.stringify({
  timestamp        : new Date().toISOString(),
  route            : 'employers_plus_info',
  event            : 'employers_plus_info_completed',
  id_funcionario   : ctx.id_funcionario,
  nome_funcionario : ctx.nome_funcionario,
  level            : 'info'
}));

return {
  statusCode: 201,
  body: {
    message          : 'Data processed and saved successfully.',
    transformed_data : ctx
  }
};

// Erro de validação
const input = $input.first().json;
return {
  statusCode: input.statusCode || 400,
  body      : input.body || { ok: false, error: 'Validation failed' }
};

// Erro de banco
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp : new Date().toISOString(),
  route     : 'employers_plus_info',
  event     : 'db_error',
  message   : errData.message || 'Unknown DB error',
  level     : 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not process employer data' }
};
